+{
+	std::string strRead;
+	char pBuf[20];
+	*pValue = false;
+	if (GetKeyValue(pSect, pKey, pBuf, 20, bWarnIfNotfound) == -1)
+		return -1;
+
+	char* pChar = pBuf;
+	while( *pChar == ' ' )	pChar++;		// skip spaces
+
