+template<class T>
+void IpaVector<T>::AssignCounter(int Size)
+{
+	this->clear();
+	for(int i=0; i<Size; i++)
+	{
+		T j = (T) i; 
+		push_back(j);
+	}
+}
+
+template<class T>
+std::string IpaVector<T>::Str() const
+{
+	std::stringstream str;
+	str << this->size() << " ";
+	for(unsigned int i=0; i<this->size(); i++)
+		str << " " << (*this)[i] ;
+	str << "\n";
+	return str.str();
+}
