+		std::cerr << "IpaVector<T>::Load: Could not load '" << Name << "'\n";
+		return RET_FAILED;
+	}
+	int Size;
+	f >> Size;
+	for(int i=0; i<Size; i++)
+	{
+		T val;
+		f >> val;
+		this->push_back(val);
+	}
+	return RET_OK;
+}
