+                else
+                {
+                    H = val * hsvBlue;
+                    S = 255;
+                    V = 255;
+                }
+
+                hsvImage.at<cv::Vec3b>(i,j)[0] = hsvBlue - H;
+                hsvImage.at<cv::Vec3b>(i,j)[1] = S;
+                hsvImage.at<cv::Vec3b>(i,j)[2] = V;
+            }
+            else
+            {
+                hsvImage.at<cv::Vec3b>(i,j) = GrayColorMap(1-val, 0, 1);
+            }
+        }
+    }
+
+    if (hsv)
+        cv::cvtColor(hsvImage, hsvImage, CV_HSV2BGR);
+
+    return hsvImage;
+}

